#!/bin/bash
function count_params ()
{
    echo "Call with $# argument(s) : $*"
    count_params  "$*"   # "$*" = single argument with all params
    count_params  "$@"   # "$@" = separate arguments
}

# Calling: ./script.sh a b c
# Output:
# Call with 3 argument(s) : a b c
# Call with 1 argument(s) : a b c    ("$*" = one word)
# Call with 3 argument(s) : a b c    ("$@" = three words)
